def generate_german_content():
    levels = {}
    topics = {
        "A1": [("Begrüßungen und Vorstellungen", "Grundlegende Begrüßungen"), ("Zahlen und Alter", "Zahlen und Altersangaben"), ("Die Familie", "Familienmitglieder"), ("Berufe", "Berufe und Arbeitsplätze"), ("Essen und Trinken", "Im Restaurant"), ("Tagesablauf", "Alltägliche Aktivitäten")],
        "A2": [("Beschreibungen", "Personen und Orte beschreiben"), ("Einkaufen", "Im Geschäft"), ("Wetter und Klima", "Über das Wetter sprechen"), ("Wegbeschreibung", "Richtungen geben"), ("Freizeit und Pläne", "Freizeitaktivitäten"), ("Gesundheit", "Beim Arzt")],
        "B1": [("Vergangenheit erzählen", "Perfekt und Präteritum"), ("Ratschläge geben", "Konjunktiv II für Ratschläge"), ("Meinungen äußern", "Diskussionen führen"), ("Reisen", "Reisevokabular"), ("Kultur", "Deutsche Kultur"), ("Medien", "Medien und Kommunikation")],
        "B2": [("Konjunktiv II Vertiefung", "Irreale Bedingungen"), ("Arbeitswelt", "Berufliches Deutsch"), ("Umwelt", "Umweltthemen"), ("Kunst und Literatur", "Kulturelle Themen"), ("Technologie", "Digitale Welt"), ("Gesellschaft", "Soziale Themen")],
        "C1": [("Textanalyse", "Kritische Textanalyse"), ("Akademisches Schreiben", "Wissenschaftliches Deutsch"), ("Sprachvarietäten", "Deutsche Dialekte"), ("Wirtschaftsdeutsch", "Geschäftskommunikation"), ("Verhandlungsführung", "Professionelle Kommunikation"), ("Literatur", "Zeitgenössische Literatur")],
        "C2": [("Akademisches Register", "Wissenschaftliche Publikationen"), ("Pragmatik", "Interkulturelle Kommunikation"), ("Übersetzung", "Sprachmittlung"), ("Rhetorik", "Redekunst"), ("Soziolinguistik", "Sprache und Gesellschaft"), ("Kreatives Schreiben", "Eigener Stil")]
    }
    for level, topic_list in topics.items():
        levels[level] = []
        for i, (title, desc) in enumerate(topic_list, 1):
            content = f"In dieser Lektion lernen Sie über {desc}.\n\n"
            if level == "A1":
                content += f"{'Lernen Sie die grundlegenden Begrüßungen auf Deutsch: Guten Morgen, Guten Tag, Guten Abend, Auf Wiedersehen. Informelle Grüße: Hallo, Tschüss, Hi. Sich vorstellen: Ich heiße..., Ich bin..., Mein Name ist...' if i==1 else 'Die Zahlen von 0 bis 100. Null, eins, zwei, drei, vier, fünf, sechs, sieben, acht, neun, zehn. Alter: Wie alt bist du? Ich bin 25 Jahre alt.' if i==2 else 'Familienmitglieder: der Vater, die Mutter, der Bruder, die Schwester, der Sohn, die Tochter, der Großvater, die Großmutter.' if i==3 else 'Berufe: der Lehrer/die Lehrerin, der Arzt/die Ärztin, der Ingenieur/die Ingenieurin. Was sind Sie von Beruf? Ich bin Lehrer.' if i==4 else 'Im Restaurant: Ich hätte gerne... Die Speisekarte, bitte. Die Rechnung, bitte. Mahlzeiten: das Frühstück, das Mittagessen, das Abendessen.' if i==5 else 'Tägliche Routine: aufstehen, duschen, frühstücken, zur Arbeit gehen, zu Mittag essen, nach Hause kommen, zu Abend essen, schlafen gehen.'}"
            elif level in ["A2", "B1"]:
                content += f"Vertiefte Inhalte über {desc} mit erweitertem Wortschatz, Grammatikstrukturen und praktischen Übungen für das Niveau {level}."
            else:
                content += f"Fortgeschrittene Inhalte für Niveau {level}: {desc}. Entwicklung komplexer sprachlicher Kompetenzen mit Fokus auf akademische und professionelle Kontexte."
            
            vocab = [
                {"word": f"Wort {j}", "translation": f"Word {j}", "example": f"Beispielsatz mit Wort {j}."}
                for j in range(1, 7)
            ]
            # Better vocabulary based on topic
            if "Begrüßung" in title:
                vocab = [{"word": "Guten Morgen", "translation": "Good morning", "example": "Guten Morgen, Herr Schmidt!"}, {"word": "Auf Wiedersehen", "translation": "Goodbye", "example": "Auf Wiedersehen! Bis morgen."}, {"word": "Bitte", "translation": "Please", "example": "Ein Kaffee, bitte."}, {"word": "Danke", "translation": "Thank you", "example": "Vielen Dank für Ihre Hilfe."}, {"word": "Wie heißen Sie?", "translation": "What's your name?", "example": "Wie heißen Sie? Ich heiße Anna."}, {"word": "Freut mich", "translation": "Nice to meet you", "example": "Freut mich, Sie kennenzulernen."}]
            
            grammar = [f"Grammatikpunkt {j} für {level} Lektion {i}" for j in range(1, 4)]
            if "Begrüßung" in title:
                grammar = ["Personalpronomen: ich, du, er/sie/es, wir, ihr, sie/Sie", "Verb SEIN: bin, bist, ist, sind, seid, sind", "Verb HEIßEN: heiße, heißt, heißt, heißen"]
            
            levels[level].append({"title": f"Lektion {i}: {title}", "content": content, "vocabulary": vocab, "grammar_points": grammar})
    return levels

def generate_french_content():
    levels = {}
